  ?series wdt:P161 wd:Q506198 .
  ?series wdt:P31 wd:Q17207188 .
  ?series wdt:P495 wd:Q30 .
  ?episode wdt:P154 ?series .
  ?episode wdt:P577 "2005-11-25"^^xsd:date .
  ?series wdt:P115 ?network .
  ?network wdt:P31 wd:Q2738342 .
  OPTIONAL { ?network rdfs:label ?networkLabel . FILTER (lang(?networkLabel) = "en") }
}

